            int type = arr[idx], val = arr[idx + 1]; idx += 2;
            if (type == 1) stack.Push(val);
            else if (type == 2) total += stack.Count > 0 ? stack.Pop() : -1;
        }
        return total;
    }
}

package stackoperations

// StackOps processes stack operations and returns sum of popped values.
func StackOps(arr []int) int {
	if len(arr) == 0 {
		return 0
	}
	stack := []int{}
	opCount := arr[0]
	idx := 1
	total := 0
	for i := 0; i < opCount; i++ {
		t := arr[idx]
		idx += 2
		if t == 1 {
			stack = append(stack, arr[idx-1])
		} else if t == 2 {
			if len(stack) > 0 {
				total += stack[len(stack)-1]
				stack = stack[:len(stack)-1]
			} else {
				total += -1
			}
		}
	}
	return total
}

import java.util.ArrayList;
import java.util.List;

public class StackOperations {

    public static int stackOps(int[] arr) {
        if (arr.length == 0) return 0;
        List<Integer> stack = new ArrayList<>();
        int opCount = arr[0], idx = 1, total = 0;
        for (int i = 0; i < opCount; i++) {
            int type = arr[idx], val = arr[idx + 1];
            idx += 2;
            if (type == 1) {
                stack.add(val);
            } else if (type == 2) {
                if (!stack.isEmpty()) total += stack.remove(stack.size() - 1);
                else total += -1;
            }
        }
        return total;
    }
}

fun stackOps(arr: IntArray): Int {
    if (arr.isEmpty()) return 0
    val stack = mutableListOf<Int>()
    val opCount = arr[0]
    var idx = 1
    var total = 0
    for (i in 0 until opCount) {
        val type = arr[idx]; val v = arr[idx + 1]; idx += 2
        if (type == 1) stack.add(v)
        else if (type == 2) total += if (stack.isNotEmpty()) stack.removeAt(stack.size - 1) else -1
    }
    return total
}

def stack_ops(arr: list[int]) -> int:
    if not arr:
        return 0
    stack: list[int] = []
    op_count = arr[0]
    idx = 1
    total = 0
    for _ in range(op_count):
        op_type = arr[idx]
        val = arr[idx + 1]
        idx += 2
        if op_type == 1:
            stack.append(val)
        elif op_type == 2:
            if stack:
                total += stack.pop()
            else:
                total += -1
    return total

pub fn stack_ops(arr: &[i32]) -> i32 {
    if arr.is_empty() { return 0; }
    let mut stack: Vec<i32> = Vec::new();
    let op_count = arr[0] as usize;
    let mut idx = 1;
    let mut total: i32 = 0;
    for _ in 0..op_count {
        let t = arr[idx];
        let v = arr[idx + 1];
        idx += 2;
        if t == 1 { stack.push(v); }
        else if t == 2 {
            total += stack.pop().unwrap_or(-1);
        }
    }
    total
}

object StackOperations {

  def stackOps(arr: Array[Int]): Int = {
    if (arr.isEmpty) return 0
    val stack = scala.collection.mutable.ArrayBuffer[Int]()
    val opCount = arr(0)
    var idx = 1
    var total = 0
    for (_ <- 0 until opCount) {
      val tp = arr(idx); val v = arr(idx + 1); idx += 2
      if (tp == 1) stack += v
      else if (tp == 2) {
        if (stack.nonEmpty) { total += stack.last; stack.remove(stack.size - 1) }
        else total += -1
      }
    }
    total
  }
}

func stackOps(_ arr: [Int]) -> Int {
    if arr.isEmpty { return 0 }
    var stack: [Int] = []
    let opCount = arr[0]
    var idx = 1, total = 0
    for _ in 0..<opCount {
        let type = arr[idx]; let v = arr[idx + 1]; idx += 2
        if type == 1 { stack.append(v) }
        else if type == 2 { total += stack.isEmpty ? -1 : stack.removeLast() }
    }
    return total
}

export function stackOps(arr: number[]): number {
    if (arr.length === 0) return 0;
    const stack: number[] = [];
    const opCount = arr[0];
    let idx = 1, total = 0;
    for (let i = 0; i < opCount; i++) {
        const type = arr[idx], val = arr[idx + 1];
        idx += 2;
        if (type === 1) stack.push(val);
        else if (type === 2) total += stack.length > 0 ? stack.pop()! : -1;
    }
    return total;
}
